export default ChatMessage;

import React, { useState, useRef, useEffect } from 'react';

interface InputAreaProps {
  onSendMessage: (text: string) => void;
  isLoading: boolean;
}

const InputArea: React.FC<InputAreaProps> = ({ onSendMessage, isLoading }) => {
  const [inputText, setInputText] = useState('');
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const handleSend = () => {
    if (inputText.trim() && !isLoading) {
      onSendMessage(inputText);
      setInputText('');
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 120)}px`;
    }
  }, [inputText]);

  return (
    <div className="bg-white border-t p-2 md:p-4 flex items-end gap-2 md:gap-4 sticky bottom-0">
      <div className="flex-1 relative bg-gray-50 rounded-2xl border border-gray-200 overflow-hidden px-3 py-1">
        <textarea
          ref={textareaRef}
          className="w-full bg-transparent border-none focus:ring-0 text-sm md:text-base resize-none max-h-[120px] py-2"
          placeholder="Message..."
          rows={1}
          value={inputText}
          onChange={(e) => setInputText(e.target.value)}
          onKeyDown={handleKeyDown}
          disabled={isLoading}
        />
        <div className="absolute left-3 bottom-2 text-gray-400">
           <i className="fa-solid fa-paperclip hover:text-gray-600 cursor-pointer"></i>
        </div>
      </div>
      <button
        onClick={handleSend}
        disabled={!inputText.trim() || isLoading}
        className={`w-12 h-12 rounded-full flex items-center justify-center transition-colors ${
          !inputText.trim() || isLoading
            ? 'bg-gray-200 text-gray-400 cursor-not-allowed'
            : 'bg-[#0088cc] text-white hover:bg-[#0077b5] cursor-pointer'
        }`}
      >
        {isLoading ? (
          <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
        ) : (
          <i className="fa-solid fa-paper-plane"></i>
        )}
      </button>
    </div>
  );
};

export default InputArea;

import React, { useState, useEffect, useRef } from 'react';
import { Message } from './types';
