import React from 'react';
import { Message } from '../types';

interface ChatMessageProps {
  message: Message;
}

const ChatMessage: React.FC<ChatMessageProps> = ({ message }) => {
  const isBot = message.role === 'model';

  // Basic markdown-to-html helper for common elements
  const renderText = (text: string) => {
    return text.split('\n').map((line, i) => {
      // Bold
      let formatted = line.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
      // Links
      formatted = formatted.replace(/(https?:\/\/[^\s]+)/g, '<a href="$1" target="_blank" class="underline text-blue-500">$1</a>');
      // Handles
      formatted = formatted.replace(/(@\w+)/g, '<span class="text-blue-600 font-semibold">$1</span>');

      return (
        <span key={i} className="block mb-1" dangerouslySetInnerHTML={{ __html: formatted }} />
      );
    });
  };

  return (
    <div className={`flex w-full mb-4 animate-fadeIn ${isBot ? 'justify-start' : 'justify-end'}`}>
      <div
        className={`relative max-w-[85%] md:max-w-[75%] px-4 py-2 rounded-2xl shadow-sm ${
          isBot 
            ? 'bg-white text-gray-800 rounded-tl-none border border-gray-100' 
            : 'bg-[#0088cc] text-white rounded-tr-none'
        }`}
      >
        <div className="text-sm md:text-base leading-relaxed break-words">
          {renderText(message.text)}
        </div>

        <div className={`text-[10px] mt-1 flex justify-end items-center gap-1 opacity-70 ${isBot ? 'text-gray-400' : 'text-blue-100'}`}>
          {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
          {!isBot && <i className="fa-solid fa-check-double text-[8px]"></i>}
        </div>

        {/* Bubble Tail */}
        <div 
          className={`absolute top-0 w-2 h-4 ${isBot ? '-left-1 bg-white' : '-right-1 bg-[#0088cc]'}`} 
          style={{ clipPath: isBot ? 'polygon(100% 0, 0 0, 100% 100%)' : 'polygon(0 0, 100% 0, 0 100%)' }}
        />
      </div>
    </div>
  );
};

export default ChatMessage;

