import React from 'react';
import { Message } from '../types';

interface ChatMessageProps {
  message: Message;
  darkMode?: boolean;
}

const ChatMessage: React.FC<ChatMessageProps> = ({ message, darkMode }) => {
  const isBot = message.role === 'model';

  const formatText = (text: string) => {
    return text.split('\n').map((line, i) => {
      // Very basic markdown parsing
      let content: React.ReactNode = line;

      // Headers
      if (line.startsWith('### ')) {
        return <h3 key={i} className="font-bold text-base mt-2 mb-1">{line.replace('### ', '')}</h3>;
      }
      if (line.startsWith('## ')) {
        return <h2 key={i} className="font-bold text-lg mt-3 mb-1 border-b border-opacity-20">{line.replace('## ', '')}</h2>;
      }
      if (line.startsWith('# ')) {
        return <h1 key={i} className="font-bold text-xl mt-4 mb-2">{line.replace('# ', '')}</h1>;
      }

      // Bold text (Basic)
      const parts = line.split(/(\*\*.*?\*\*)/);
      const formattedParts = parts.map((part, index) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={index}>{part.slice(2, -2)}</strong>;
        }
        return part;
      });

      return <p key={i} className="min-h-[1em] mb-0.5">{formattedParts}</p>;
    });
  };

  return (
    <div className={`flex w-full mb-4 ${isBot ? 'justify-start' : 'justify-end'} animate-fadeIn`}>
      <div
        className={`max-w-[85%] md:max-w-[75%] px-4 py-2 rounded-2xl shadow-sm relative transition-colors duration-200 ${
          isBot 
            ? darkMode 
              ? 'bg-[#182533] text-white rounded-tl-none border border-gray-800' 
              : 'bg-white text-gray-800 rounded-tl-none border border-gray-100' 
            : darkMode
              ? 'bg-[#2b5278] text-white rounded-tr-none'
              : 'bg-[#0088cc] text-white rounded-tr-none'
        }`}
      >
        <div className="break-words text-sm md:text-base leading-relaxed">
          {formatText(message.text)}
        </div>
        <div className={`text-[10px] mt-1 flex justify-end items-center gap-1 ${
          isBot 
            ? darkMode ? 'text-gray-400' : 'text-gray-400' 
            : darkMode ? 'text-blue-200' : 'text-blue-100'
        }`}>
          {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
          {!isBot && <i className="fa-solid fa-check-double text-[8px]"></i>}
        </div>

        {/* Tail adjustment for telegram feel */}
        <div className={`absolute top-0 w-2 h-4 ${
          isBot 
            ? darkMode 
              ? '-left-1 bg-[#182533]' 
              : '-left-1 bg-white' 
            : darkMode
              ? '-right-1 bg-[#2b5278]'
              : '-right-1 bg-[#0088cc]'
          }`} 
          style={{ clipPath: isBot ? 'polygon(100% 0, 0 0, 100% 100%)' : 'polygon(0 0, 100% 0, 0 100%)' }}>
        </div>
      </div>
    </div>
  );
};

